def valid_sudoku_3x3(grid):
    if len(grid) != 3:
        return False
    for row in grid:
        if len(row) != 3:
            return False
    seen = set()
    for row in grid:
        for num in row:
            if num < 1 or num > 9:
                return False
            if num in seen:
                return False
            seen.add(num)
    return True
